import pygame
import random

class Tetris:
    def __init__(self, width=10, height=20):
        self.width = width
        self.height = height
        self.grid = [[0 for _ in range(width)] for _ in range(height)]
        self.players = [Player(i) for i in range(3)]
        self.current_player = 0
        self.score = 0

    def draw_grid(self, screen):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x] == 1:
                    pygame.draw.rect(screen, (255, 0, 0), (x * 30, y * 30, 30, 30), 0)

    def update(self):
        self.players[self.current_player].update(self)
        if self.players[self.current_player].piece is None:
            self.current_player = (self.current_player + 1) % 3

    def add_piece(self, piece):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x] == 1 and piece.collide(self.grid, x, y):
                    return False
        for y in range(self.height):
            for x in range(self.width):
                if piece.collide(self.grid, x, y):
                    self.grid[y][x] = 1
        return True

    def remove_row(self, row):
        del self.grid[row]
        self.grid.insert(0, [0 for _ in range(self.width)])

    def check_rows(self):
        rows_to_remove = []
        for y in range(self.height):
            if all(self.grid[y]):
                rows_to_remove.append(y)
        for row in sorted(rows_to_remove, reverse=True):
            self.remove_row(row)
        self.score += len(rows_to_remove)

class Player:
    def __init__(self, id):
        self.id = id
        self.piece = None
        self.score = 0

    def update(self, game):
        if self.piece is None:
            self.piece = Piece()
        keys = pygame.key.get_pressed()
        if keys[pygame.K_LEFT]:
            self.piece.move_left(game.grid)
        if keys[pygame.K_RIGHT]:
            self.piece.move_right(game.grid)
        if keys[pygame.K_DOWN]:
            self.piece.move_down(game.grid)
        if keys[pygame.K_UP]:
            self.piece.rotate(game.grid)
        if self.piece.is_at_bottom(game.grid):
            game.add_piece(self.piece)
            self.score += 1
            self.piece = None

class Piece:
    def __init__(self):
        self.x = 5
        self.y = 0
        self.type = random.randint(0, 6)
        self.color = (random.randint(0, 255), random.randint(0, 255), random.randint(0, 255))

    def collide(self, grid, x, y):
        if x < 0 or x >= len(grid[0]) or y < 0 or y >= len(grid):
            return True
        if grid[y][x] == 1:
            return True
        return False

    def move_left(self, grid):
        if not self.collide(grid, self.x - 1, self.y):
            self.x -= 1

    def move_right(self, grid):
        if not self.collide(grid, self.x + 1, self.y):
            self.x += 1

    def move_down(self, grid):
        if not self.collide(grid, self.x, self.y + 1):
            self.y += 1

    def rotate(self, grid):
        if self.type == 0:
            if not self.collide(grid, self.x, self.y + 1) and not self.collide(grid, self.x + 1, self.y + 1):
                self.y += 1
                self.x += 1
        elif self.type == 1:
            if not self.collide(grid, self.x - 1, self.y) and not self.collide(grid, self.x - 1, self.y + 1):
                self.x -= 1
                self.y += 1
        elif self.type == 2:
            if not self.collide(grid, self.x, self.y - 1) and not self.collide(grid, self.x + 1, self.y - 1):
                self.y -= 1
                self.x += 1
        elif self.type == 3:
            if not self.collide(grid, self.x + 1, self.y) and not self.collide(grid, self.x + 1, self.y - 1):
                self.x += 1
                self.y -= 1
        elif self.type == 4:
            if not self.collide(grid, self.x, self.y + 1) and not self.collide(grid, self.x - 1, self.y + 1):
                self.y += 1
                self.x -= 1
        elif self.type == 5:
            if not self.collide(grid, self.x + 1, self.y) and not self.collide(grid, self.x + 1, self.y + 1):
                self.x += 1
                self.y += 1
        elif self.type == 6:
            if not self.collide(grid, self.x - 1, self.y) and not self.collide(grid, self.x - 1, self.y - 1):
                self.x -= 1
                self.y -= 1

    def is_at_bottom(self, grid):
        if self.y + 1 >= len(grid):
            return True
        if self.collide(grid, self.x, self.y + 1):
            return True
        return False

def main():
    pygame.init()
    screen = pygame.display.set_mode((300, 600))
    clock = pygame.time.Clock()
    game = Tetris()
    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
        game.update()
        game.check_rows()
        screen.fill((0, 0, 0))
        game.draw_grid(screen)
        for player in game.players:
            font = pygame.font.Font(None, 36)
            text = font.render(f"Player {player.id + 1}: {player.score}", True, (255, 255, 255))
            screen.blit(text, (10, 10 + player.id * 30))
        font = pygame.font.Font(None, 36)
        text = font.render(f"Score: {game.score}", True, (255, 255, 255))
        screen.blit(text, (10, 100))
        pygame.display.flip()
        clock.tick(60)
    pygame.quit()

if __name__ == "__main__":
    main()

