                    tetris.players[tetris.current_player].piece.x -= 1
                elif event.key == pygame.K_RIGHT:
                    tetris.players[tetris.current_player].piece.x += 1
                elif event.key == pygame.K_DOWN:
                    tetris.players[tetris.current_player].piece.y += 1
                elif event.key == pygame.K_UP:
                    tetris.players[tetris.current_player].piece.y -= 1
        tetris.update()
