        rows_to_remove = []
        for i, row in enumerate(self.grid):
            if all(row):
                rows_to_remove.append(i)
        for row in sorted(rows_to_remove, reverse=True):
            self.remove_row(row)
            self.score += 1
            for player in self.players:
                if player.contribution > 0:
                    player.score += 1
                    player.contribution -= 1

    def update(self):
        self.check_rows()

class Player:
