import pygame
import random

class Tetris:
    def __init__(self, width=10, height=20):
        self.width = width
        self.height = height
        self.grid = [[0]*width for _ in range(height)]
        self.score = [0, 0, 0]
        self.contribution = [0, 0, 0]
        self.current_piece = None
        self.next_piece = self.generate_piece()
        self.player_turn = 0

    def generate_piece(self):
        shapes = [
            [[1, 1, 1, 1]],  # I
            [[1, 1], [1, 1]],  # O
            [[1, 1, 0], [0, 1, 1]],  # S
            [[0, 1, 1], [1, 1, 0]],  # Z
            [[1, 1, 1], [0, 1, 0]],  # T
            [[1, 1, 1], [1, 0, 0]],  # J
            [[1, 1, 1], [0, 0, 1]]   # L
        ]
        return random.choice(shapes)

    def rotate_piece(self):
        if self.current_piece is not None:
            self.current_piece = [list(reversed(i)) for i in zip(*self.current_piece)]

    def move_piece(self, direction):
        if self.current_piece is not None:
            if direction == 'left':
                for row in self.current_piece:
                    for i, cell in enumerate(row):
                        if cell == 1:
                            if i == 0:
                                return
                            row[i-1] = cell
                            row[i] = 0
            elif direction == 'right':
                for row in self.current_piece:
                    for i, cell in enumerate(reversed(row)):
                        if cell == 1:
                            if i == 0:
                                return
                            row[len(row)-i] = 0
                            row[len(row)-i-1] = cell
            elif direction == 'down':
                for i, row in enumerate(self.current_piece):
                    if i == len(self.current_piece) - 1:
                        for j, cell in enumerate(row):
                            if cell == 1:
                                if i + 1 >= self.height:
                                    return
                                self.grid[i+1][j] = cell
                                row[j] = 0

    def place_piece(self):
        if self.current_piece is not None:
            for i, row in enumerate(self.current_piece):
                for j, cell in enumerate(row):
                    if cell == 1:
                        self.grid[i][j] = cell
            self.current_piece = None
            self.next_piece = self.generate_piece()

    def check_for_clear(self):
        cleared = 0
        for row in self.grid:
            if all(cell == 1 for cell in row):
                self.grid.remove(row)
                self.grid.insert(0, [0]*self.width)
                cleared += 1
        self.score[self.player_turn] += cleared * cleared
        self.contribution[self.player_turn] += cleared
        self.player_turn = (self.player_turn + 1) % 3

    def draw(self, screen):
        screen.fill((0, 0, 0))
        for i, row in enumerate(self.grid):
            for j, cell in enumerate(row):
                if cell == 1:
                    pygame.draw.rect(screen, (255, 255, 255), (j*30, i*30, 30, 30))
        if self.current_piece is not None:
            for i, row in enumerate(self.current_piece):
                for j, cell in enumerate(row):
                    if cell == 1:
                        pygame.draw.rect(screen, (255, 255, 255), (j*30, i*30, 30, 30))
        for i, score in enumerate(self.score):
            font = pygame.font.Font(None, 36)
            text = font.render(f'Player {i+1}: {score}', True, (255, 255, 255))
            screen.blit(text, (10, 10 + i*40))
        for i, contribution in enumerate(self.contribution):
            font = pygame.font.Font(None, 36)
            text = font.render(f'Player {i+1} contribution: {contribution}', True, (255, 255, 255))
            screen.blit(text, (200, 10 + i*40))
        pygame.display.flip()

def main():
    pygame.init()
    screen = pygame.display.set_mode((600, 600))
    clock = pygame.time.Clock()
    tetris = Tetris()
    tetris.current_piece = tetris.generate_piece()
    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
