import pygame
import random

class Tetris:
    def __init__(self, width=10, height=20):
        self.width = width
        self.height = height
        self.grid = [[0 for _ in range(width)] for _ in range(height)]
        self.score = 0
        self.players = [Player(i) for i in range(3)]

    def add_piece(self, piece, x, y, player_id):
        for i, row in enumerate(piece):
            for j, val in enumerate(row):
                if val:
                    self.grid[y + i][x + j] = player_id + 1

    def remove_row(self, row):
        del self.grid[row]
        self.grid.insert(0, [0 for _ in range(self.width)])

    def check_rows(self):
        rows_to_remove = []
        for i, row in enumerate(self.grid):
            if all(cell!= 0 for cell in row):
                rows_to_remove.append(i)
        for row in sorted(rows_to_remove, reverse=True):
            self.remove_row(row)
            self.score += 1
            for player in self.players:
                if player.last_move_removed_row:
                    player.score += 1
                    player.last_move_removed_row = False

    def update(self, piece, x, y, player_id):
        self.add_piece(piece, x, y, player_id)
        self.check_rows()
        self.players[player_id].last_move_removed_row = True

class Player:
    def __init__(self, id):
        self.id = id
        self.score = 0
        self.last_move_removed_row = False

class Piece:
    def __init__(self, shape):
        self.shape = shape

    def rotate(self):
        self.shape = [list(reversed(col)) for col in zip(*self.shape)]

def draw_grid(screen, grid, cell_size):
    for i, row in enumerate(grid):
        for j, val in enumerate(row):
            if val!= 0:
                pygame.draw.rect(screen, (255, 0, 0), (j * cell_size, i * cell_size, cell_size, cell_size), 0)

def draw_text(screen, text, x, y, font_size):
    font = pygame.font.SysFont('Arial', font_size)
    text_surface = font.render(text, True, (255, 255, 255))
    screen.blit(text_surface, (x, y))

def main():
    pygame.init()
    screen_width = 800
    screen_height = 600
    screen = pygame.display.set_mode((screen_width, screen_height))
    clock = pygame.time.Clock()
    tetris = Tetris()
    pieces = [Piece([[1, 1], [1, 1]]), Piece([[1, 1, 1], [0, 1, 0]]), Piece([[1, 1, 1, 1]])]
    current_piece = random.choice(pieces)
    x, y = 0, 0
    player_id = 0
    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    x -= 1
                elif event.key == pygame.K_RIGHT:
                    x += 1
                elif event.key == pygame.K_DOWN:
                    y += 1
                elif event.key == pygame.K_UP:
                    current_piece.rotate()
                elif event.key == pygame.K_SPACE:
                    tetris.update(current_piece.shape, x, y, player_id)
                    current_piece = random.choice(pieces)
                    x, y = 0, 0
                    player_id = (player_id + 1) % 3
        screen.fill((0, 0, 0))
