            pygame.draw.rect(screen, (255, 0, 0), ((self.x + 2) * 30, (self.y + 1) * 30, 30, 30))
        font = pygame.font.Font(None, 36)
        text = font.render(f'Score: {self.tetris.score[0]} {self.tetris.score[1]} {self.tetris.score[2]}', True, (255, 255, 255))
        screen.blit(text, (10, 10))

    def handle_event(self, event):
        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_LEFT:
                if not self.tetris.check_collision(self.x - 1, self.y, self.piece):
                    self.x -= 1
            elif event.key == pygame.K_RIGHT:
                if not self.tetris.check_collision(self.x + 1, self.y, self.piece):
                    self.x += 1
            elif event.key == pygame.K_DOWN:
                if not self.tetris.check_collision(self.x, self.y + 1, self.piece):
                    self.y += 1
            elif event.key == pygame.K_UP:
                self.piece = self.tetris.rotate_piece(self.piece)
            elif event.key == pygame.K_SPACE:
                self.tetris.place_piece(self.x, self.y, self.piece)
                if self.tetris.check_row():
                    self.tetris.switch_player()
                self.piece = self.tetris.new_piece()
                self.x = self.tetris.width // 2
                self.y = 0

def main():
    pygame.init()
    screen = pygame.display.set_mode((300, 600))
    clock = pygame.time.Clock()
    game = Game()
    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            game.handle_event(event)
        game.draw(screen)
        pygame.display.flip()
        clock.tick(60)
