        return random.choice(['I', 'J', 'L', 'O', 'S', 'T', 'Z'])

    def rotate_piece(self, piece):
        if piece == 'I':
            return 'I'
        elif piece == 'J':
            return 'L'
        elif piece == 'L':
            return 'J'
        elif piece == 'O':
            return 'O'
        elif piece == 'S':
            return 'Z'
        elif piece == 'T':
            return 'T'
        elif piece == 'Z':
            return 'S'

    def check_collision(self, x, y, piece):
        if piece == 'I':
            if x < 0 or x > self.width - 4 or y < 0 or y > self.height - 1:
                return True
            for i in range(4):
                if self.grid[y][x + i] == 1:
                    return True
        elif piece == 'J':
            if x < 0 or x > self.width - 3 or y < 0 or y > self.height - 2:
                return True
            if self.grid[y][x] == 1 or self.grid[y][x + 1] == 1 or self.grid[y][x + 2] == 1 or self.grid[y + 1][x + 2] == 1:
                return True
        elif piece == 'L':
            if x < 0 or x > self.width - 3 or y < 0 or y > self.height - 2:
                return True
            if self.grid[y][x] == 1 or self.grid[y][x + 1] == 1 or self.grid[y][x + 2] == 1 or self.grid[y + 1][x] == 1:
                return True
        elif piece == 'O':
            if x < 0 or x > self.width - 2 or y < 0 or y > self.height - 2:
                return True
            if self.grid[y][x] == 1 or self.grid[y][x + 1] == 1 or self.grid[y + 1][x] == 1 or self.grid[y + 1][x + 1] == 1:
                return True
        elif piece == 'S':
            if x < 0 or x > self.width - 3 or y < 0 or y > self.height - 2:
                return True
            if self.grid[y][x + 1] == 1 or self.grid[y][x + 2] == 1 or self.grid[y + 1][x] == 1 or self.grid[y + 1][x + 1] == 1:
                return True
        elif piece == 'T':
            if x < 0 or x > self.width - 3 or y < 0 or y > self.height - 2:
                return True
            if self.grid[y][x] == 1 or self.grid[y][x + 1] == 1 or self.grid[y][x + 2] == 1 or self.grid[y + 1][x + 1] == 1:
                return True
        elif piece == 'Z':
            if x < 0 or x > self.width - 3 or y < 0 or y > self.height - 2:
                return True
            if self.grid[y][x] == 1 or self.grid[y][x + 1] == 1 or self.grid[y + 1][x + 1] == 1 or self.grid[y + 1][x + 2] == 1:
                return True
        return False

    def place_piece(self, x, y, piece):
        if piece == 'I':
            for i in range(4):
                self.grid[y][x + i] = 1
        elif piece == 'J':
            self.grid[y][x] = 1
            self.grid[y][x + 1] = 1
            self.grid[y][x + 2] = 1
            self.grid[y + 1][x + 2] = 1
        elif piece == 'L':
            self.grid[y][x] = 1
            self.grid[y][x + 1] = 1
            self.grid[y][x + 2] = 1
            self.grid[y + 1][x] = 1
        elif piece == 'O':
            self.grid[y][x] = 1
            self.grid[y][x + 1] = 1
            self.grid[y + 1][x] = 1
            self.grid[y + 1][x + 1] = 1
        elif piece == 'S':
            self.grid[y][x + 1] = 1
            self.grid[y][x + 2] = 1
            self.grid[y + 1][x] = 1
            self.grid[y + 1][x + 1] = 1
        elif piece == 'T':
            self.grid[y][x] = 1
            self.grid[y][x + 1] = 1
            self.grid[y][x + 2] = 1
            self.grid[y + 1][x + 1] = 1
        elif piece == 'Z':
            self.grid[y][x] = 1
            self.grid[y][x + 1] = 1
            self.grid[y + 1][x + 1] = 1
            self.grid[y + 1][x + 2] = 1

    def check_row(self):
        rows = 0
        for y in range(self.height):
            if all(cell == 1 for cell in self.grid[y]):
                rows += 1
                self.grid.pop(y)
                self.grid.insert(0, [0 for _ in range(self.width)])
        return rows

    def update_score(self, rows):
        self.score[self.player_turn] += rows * rows

    def switch_player(self):
        self.player_turn = (self.player_turn + 1) % 3

