class Tetris:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0 for _ in range(width)] for _ in range(height)]
        self.player1_score = 0
        self.player2_score = 0
        self.player3_score = 0
        self.player1_donation = 0
        self.player2_donation = 0
        self.player3_donation = 0
        self.total_score = 0

    def new_piece(self):
        return random.choice(['I', 'J', 'L', 'O', 'S', 'T', 'Z'])

    def rotate_piece(self, piece):
        if piece == 'I':
            return 'I'
        elif piece == 'J':
            return 'L'
        elif piece == 'L':
            return 'J'
        elif piece == 'O':
            return 'O'
        elif piece == 'S':
            return 'Z'
        elif piece == 'T':
            return 'T'
        elif piece == 'Z':
            return 'S'

    def remove_row(self, row):
        del self.grid[row]
        self.grid.insert(0, [0 for _ in range(self.width)])

    def update_score(self, player, score):
        if player == 1:
            self.player1_score += score
        elif player == 2:
            self.player2_score += score
        elif player == 3:
            self.player3_score += score
        self.total_score += score

    def calculate_donation(self):
        self.player1_donation = (self.player1_score / self.total_score) * 100
        self.player2_donation = (self.player2_score / self.total_score) * 100
        self.player3_donation = (self.player3_score / self.total_score) * 100

