                if event.key == pygame.K_p:
                    self.game.update_score(1, 100)
                    self.game.calculate_donation()
                elif event.key == pygame.K_o:
                    self.game.update_score(2, 100)
                    self.game.calculate_donation()
                elif event.key == pygame.K_i:
                    self.game.update_score(3, 100)
                    self.game.calculate_donation()

    def run(self):
        while True:
            self.screen.fill(self.background_color)
            self.draw_grid()
            self.draw_scores()
