        for y, row in enumerate(self.piece):
            for x, val in enumerate(row):
                if val == 1:
                    pygame.draw.rect(self.screen, (255, 255, 255), ((self.piece_x + x) * 30, (self.piece_y + y) * 30, 30, 30), 0)

    def update(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                quit()
