                elif event.key == pygame.K_SPACE:
                    self.drop_piece()
                elif event.key == pygame.K_p:
                    self.player_turn = (self.player_turn + 1) % 3

        self.screen.fill((0, 0, 0))
        self.draw_grid()
        self.draw_piece()
        self.draw_score()
        self.update_piece()
        pygame.display.update()
        self.clock.tick(60)

    def move_piece(self, dx, dy):
        if self.is_valid_move(self.piece_x + dx, self.piece_y + dy):
            self.piece_x += dx
            self.piece_y += dy

    def drop_piece(self):
        while self.is_valid_move(self.piece_x, self.piece_y + 1):
            self.piece_y += 1
        self.lock_piece()

