import random

class Tetris:
    def __init__(self, width=10, height=20):
        self.width = width
        self.height = height
        self.grid = [[0 for _ in range(width)] for _ in range(height)]
        self.players = []
        self.player_turn = 0
        self.block_types = ['I', 'J', 'L', 'O', 'S', 'T', 'Z']
        self.current_block = None
        self.score = 0
        self.contributions = {'player1': 0, 'player2': 0, 'player3': 0}

    def add_player(self, name):
        self.players.append(name)

    def start_game(self):
        self.current_block = self.get_random_block()

    def get_random_block(self):
        block_type = random.choice(self.block_types)
        return Block(block_type, self.width // 2, 0)

    def move_block(self, direction):
        if direction == 'left' and self.current_block.x > 0:
            self.current_block.x -= 1
        elif direction == 'right' and self.current_block.x < self.width - self.current_block.width:
            self.current_block.x += 1
        elif direction == 'down' and self.current_block.y < self.height - self.current_block.height:
            self.current_block.y += 1

    def rotate_block(self):
        self.current_block.rotate()

    def place_block(self):
        self.grid[self.current_block.y][self.current_block.x] = 1
        self.score += 1
        self.contributions[self.players[self.player_turn]] += 1
        self.current_block = self.get_random_block()

    def check_line(self):
        lines = 0
        for row in self.grid:
            if all(cell == 1 for cell in row):
                lines += 1
        return lines

    def render(self, screen):
        screen.fill((255, 255, 255))
        for y, row in enumerate(self.grid):
            for x, cell in enumerate(row):
                if cell == 1:
                    pygame.draw.rect(screen, (0, 0, 0), (x * 20, y * 20, 20, 20))
        self.current_block.render(screen)

class Block:
    def __init__(self, block_type, x, y):
        self.block_type = block_type
        self.x = x
        self.y = y
        self.width = 1
        self.height = 1

    def rotate(self):
        if self.block_type == 'I':
            self.width, self.height = self.height, self.width

    def render(self, screen):
        pygame.draw.rect(screen, (0, 0, 0), (self.x * 20, self.y * 20, self.width * 20, self.height * 20))

