        self.current_shape = random.choice(self.shapes)
        self.current_shape_x = width // 2
        self.current_shape_y = 0
        self.game_over = False

    def draw_grid(self, screen):
        for i in range(self.height):
            for j in range(self.width):
                if self.grid[i][j] != 0:
                    pygame.draw.rect(screen, self.shape_colors[self.grid[i][j] - 1], (j * 30, i * 30, 30, 30))

    def draw_shape(self, screen):
        shape = self.get_shape(self.current_shape)
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j] == 1:
                    pygame.draw.rect(screen, self.shape_colors[self.shapes.index(self.current_shape)], ((self.current_shape_x + j) * 30, (self.current_shape_y + i) * 30, 30, 30))

    def get_shape(self, shape):
        if shape == 'I':
            return [[1, 1, 1, 1]]
        elif shape == 'J':
            return [[1, 0, 0], [1, 1, 1]]
        elif shape == 'L':
            return [[0, 0, 1], [1, 1, 1]]
        elif shape == 'O':
            return [[1, 1], [1, 1]]
        elif shape == 'S':
            return [[0, 1, 1], [1, 1, 0]]
        elif shape == 'T':
            return [[0, 1, 0], [1, 1, 1]]
        elif shape == 'Z':
            return [[1, 1, 0], [0, 1, 1]]

    def update(self):
        self.current_shape_y += 1
        if self.current_shape_y + len(self.get_shape(self.current_shape)) > self.height:
            self.current_shape_y = 0
            self.current_shape_x = self.width // 2
            self.current_shape = random.choice(self.shapes)
            self.add_shape_to_grid()
        for i in range(len(self.get_shape(self.current_shape))):
