                    if self.current_shape_x + j < 0 or self.current_shape_x + j >= self.width or self.current_shape_y + i >= self.height or self.grid[self.current_shape_y + i][self.current_shape_x + j] != 0:
                        self.current_shape_y -= 1
                        self.add_shape_to_grid()
                        break

    def add_shape_to_grid(self):
        for i in range(len(self.get_shape(self.current_shape))):
            for j in range(len(self.get_shape(self.current_shape)[0])):
                if self.get_shape(self.current_shape)[i][j] == 1:
                    self.grid[self.current_shape_y + i][self.current_shape_x + j] = self.shapes.index(self.current_shape) + 1
        self.clear_rows()
        self.switch_player()

    def clear_rows(self):
        rows_to_clear = []
        for i in range(self.height):
            if all(cell != 0 for cell in self.grid[i]):
                rows_to_clear.append(i)
        for row in rows_to_clear:
            self.grid.pop(row)
            self.grid.insert(0, [0 for _ in range(self.width)])
            if self.current_player == 1:
                self.player1_score += 1
            elif self.current_player == 2:
                self.player2_score += 1
            elif self.current_player == 3:
                self.player3_score += 1

    def switch_player(self):
        if self.current_player == 1:
