            self.current_shape_x -= 1
        elif key == pygame.K_RIGHT:
            self.current_shape_x += 1
        elif key == pygame.K_DOWN:
            self.update()
        elif key == pygame.K_UP:
            self.current_shape = random.choice(self.shapes)

