class Tetris:
    def __init__(self, width=10, height=20):
        self.width = width
        self.height = height
        self.grid = [[0 for _ in range(width)] for _ in range(height)]
        self.score = [0, 0, 0]
        self.player_turn = 0
        self.figures = [
            [[1, 5, 9, 13], [4, 5, 6, 7]],
            [[4, 5, 9, 10], [2, 6, 5, 9]],
            [[6, 7, 9, 10], [1, 5, 6, 10]],
            [[1, 2, 5, 9], [0, 4, 5, 6], [1, 5, 9, 8], [4, 5, 6, 10]],
            [[1, 2, 6, 10], [5, 6, 7, 9], [2, 6, 10, 11], [3, 5, 6, 7]],
            [[1, 4, 5, 6], [1, 4, 5, 9], [4, 5, 6, 9], [1, 5, 6, 9]],
            [[1, 2, 5, 6]],
        ]
        self.figure = random.choice(self.figures)
        self.figure_x = self.width // 2
        self.figure_y = 0

    def new_figure(self):
        self.figure = random.choice(self.figures)
        self.figure_x = self.width // 2
        self.figure_y = 0

    def intersect(self, x, y):
        figure = self.figure
        for i in range(len(figure)):
            for j in range(len(figure[i])):
                if figure[i][j] == 1:
                    if x + j < 0 or x + j >= self.width or y + i < 0 or y + i >= self.height or self.grid[y + i][x + j] == 1:
                        return True
        return False

    def break_lines(self):
        lines = 0
        for i in range(self.height):
            if all(cell == 1 for cell in self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0 for _ in range(self.width)])
                lines += 1
        return lines

    def rotate(self):
        self.figure = list(zip(*self.figure[::-1]))

    def move_down(self):
        if self.intersect(self.figure_x, self.figure_y + 1):
            self.freeze()
            return False
        self.figure_y += 1
        return True

    def move_side(self, dx):
        if self.intersect(self.figure_x + dx, self.figure_y):
            return False
        self.figure_x += dx
        return True

    def freeze(self):
        figure = self.figure
        for i in range(len(figure)):
            for j in range(len(figure[i])):
                if figure[i][j] == 1:
                    self.grid[self.figure_y + i][self.figure_x + j] = 1
        self.score[self.player_turn] += self.break_lines()
        self.player_turn = (self.player_turn + 1) % 3
        self.new_figure()

    def draw_text(self, screen, text, font, color, x, y):
        img = font.render(text, True, color)
        screen.blit(img, (x, y))

