        size = self.shape_sizes[shape]
        if size == 2:
            self.board[y][x] = shape
            self.board[y][x+1] = shape
        elif size == 3:
            self.board[y][x] = shape
            self.board[y][x+1] = shape
            self.board[y][x+2] = shape
        elif size == 4:
            self.board[y][x] = shape
