import tkinter as tk
from random import randint

class Tetris:
    def __init__(self):
        self.root = tk.Tk()
        self.root.title("Tetris")
        self.canvas = tk.Canvas(self.root, width=400, height=400)
        self.canvas.pack()
        self.player1_score = 0
        self.player2_score = 0
        self.player3_score = 0
        self.current_player = 1
        self.x = 50
        self.y = 50
        self.block_size = 20
        self.block_type = randint(1, 7)
        self.create_menu()

    def create_menu(self):
        self.menu = tk.Frame(self.root)
        self.menu.pack()
        self.player1_label = tk.Label(self.menu, text="Player 1 Score: 0")
        self.player1_label.pack(side=tk.LEFT)
        self.player2_label = tk.Label(self.menu, text="Player 2 Score: 0")
        self.player2_label.pack(side=tk.LEFT)
        self.player3_label = tk.Label(self.menu, text="Player 3 Score: 0")
        self.player3_label.pack(side=tk.LEFT)
        self.current_player_label = tk.Label(self.menu, text="Current Player: 1")
        self.current_player_label.pack(side=tk.LEFT)

    def draw_block(self):
        if self.block_type == 1:
            self.canvas.create_rectangle(self.x, self.y, self.x + self.block_size, self.y + self.block_size, fill="blue")
        elif self.block_type == 2:
            self.canvas.create_rectangle(self.x, self.y, self.x + self.block_size, self.y + self.block_size, fill="red")
        elif self.block_type == 3:
            self.canvas.create_rectangle(self.x, self.y, self.x + self.block_size, self.y + self.block_size, fill="green")
        elif self.block_type == 4:
            self.canvas.create_rectangle(self.x, self.y, self.x + self.block_size, self.y + self.block_size, fill="yellow")
        elif self.block_type == 5:
            self.canvas.create_rectangle(self.x, self.y, self.x + self.block_size, self.y + self.block_size, fill="orange")
        elif self.block_type == 6:
            self.canvas.create_rectangle(self.x, self.y, self.x + self.block_size, self.y + self.block_size, fill="purple")
        elif self.block_type == 7:
            self.canvas.create_rectangle(self.x, self.y, self.x + self.block_size, self.y + self.block_size, fill="pink")

    def update_score(self, player):
        if player == 1:
            self.player1_score += 1
            self.player1_label['text'] = f"Player 1 Score: {self.player1_score}"
        elif player == 2:
            self.player2_score += 1
            self.player2_label['text'] = f"Player 2 Score: {self.player2_score}"
        elif player == 3:
            self.player3_score += 1
            self.player3_label['text'] = f"Player 3 Score: {self.player3_score}"

    def switch_player(self):
        if self.current_player == 1:
            self.current_player = 2
        elif self.current_player == 2:
            self.current_player = 3
        elif self.current_player == 3:
            self.current_player = 1
        self.current_player_label['text'] = f"Current Player: {self.current_player}"

    def play_game(self):
        self.draw_block()
        self.update_score(self.current_player)
        self.switch_player()
        self.root.after(1000, self.play_game)

    def run(self):
        self.play_game()
        self.root.mainloop()

if __name__ == "__main__":
    game = Tetris()
    game.run()

