            return [[1, 1, 1, 1]]
        elif block_type == "J":
            return [[1, 0, 0], [1, 1, 1]]
        elif block_type == "L":
            return [[0, 0, 1], [1, 1, 1]]
        elif block_type == "O":
            return [[1, 1], [1, 1]]
        elif block_type == "S":
            return [[0, 1, 1], [1, 1, 0]]
        elif block_type == "T":
            return [[0, 1, 0], [1, 1, 1]]
        elif block_type == "Z":
            return [[1, 1, 0], [0, 1, 1]]

    def draw_grid(self):
        for y in range(self.grid_height):
            for x in range(self.grid_width):
                if self.grid[y][x] == 1:
                    pygame.draw.rect(screen, (255, 255, 255), (x * self.block_size, y * self.block_size, self.block_size, self.block_size))

