                elif event.key == pygame.K_UP:
                    self.rotate_block()
                elif event.key == pygame.K_SPACE:
                    self.drop_block()

        screen.fill((0, 0, 0))
        self.draw_grid()
        self.draw_block()
        self.draw_score()
        pygame.display.update()

