import tkinter as tk
from random import randint

class Tetris:
    def __init__(self):
        self.root = tk.Tk()
        self.root.title("Tetris")
        self.canvas = tk.Canvas(self.root, width=400, height=400)
        self.canvas.pack()
        self.player1_score = 0
        self.player2_score = 0
        self.player3_score = 0
        self.player_turn = 1
        self.block_size = 20
        self.blocks = []
        self.create_blocks()

    def create_blocks(self):
        for i in range(10):
            for j in range(10):
                block = self.canvas.create_rectangle(i * self.block_size, j * self.block_size, (i + 1) * self.block_size, (j + 1) * self.block_size, fill="gray")
                self.blocks.append(block)

    def draw_tetris(self):
        self.canvas.delete("all")
        self.create_blocks()
        self.canvas.create_text(200, 20, text="Player 1 Score: " + str(self.player1_score))
        self.canvas.create_text(200, 40, text="Player 2 Score: " + str(self.player2_score))
        self.canvas.create_text(200, 60, text="Player 3 Score: " + str(self.player3_score))
        self.canvas.create_text(200, 80, text="Player " + str(self.player_turn) + "'s turn")

    def update_score(self):
        if self.player_turn == 1:
            self.player1_score += 1
        elif self.player_turn == 2:
            self.player2_score += 1
        else:
            self.player3_score += 1

    def switch_player(self):
        if self.player_turn == 1:
            self.player_turn = 2
        elif self.player_turn == 2:
            self.player_turn = 3
        else:
            self.player_turn = 1

    def calculate_contribution(self):
        total_score = self.player1_score + self.player2_score + self.player3_score
        if total_score == 0:
            return "No scores yet"
        else:
            player1_contribution = (self.player1_score / total_score) * 100
            player2_contribution = (self.player2_score / total_score) * 100
            player3_contribution = (self.player3_score / total_score) * 100
            return "Player 1 contribution: " + str(player1_contribution) + "%, Player 2 contribution: " + str(player2_contribution) + "%, Player 3 contribution: " + str(player3_contribution) + "%"

    def play_game(self):
        self.draw_tetris()
        self.root.update()
        self.root.after(1000, self.game_loop)

    def game_loop(self):
        self.update_score()
        self.draw_tetris()
        self.root.update()
        self.switch_player()
        self.root.after(1000, self.game_loop)

    def run(self):
        self.play_game()
        self.root.mainloop()

if __name__ == "__main__":
    game = Tetris()
    game.run()

class TetrisGame:
    def __init__(self):
        self.players = ["Player1", "Player2", "Player3"]
        self.scores = {player: 0 for player in self.players}
        self.lines_cleared = {player: 0 for player in self.players}

    def update_scores(self, player, lines_cleared):
        self.scores[player] += lines_cleared * 100
        self.lines_cleared[player] += lines_cleared

    def get_player_score(self, player):
        return self.scores[player]

    def get_player_lines_cleared(self, player):
        return self.lines_cleared[player]

    def get_contribution(self, player):
        total_lines_cleared = sum(self.lines_cleared.values())
        if total_lines_cleared == 0:
            return 0
        return (self.lines_cleared[player] / total_lines_cleared) * 100


