        self.game.update_scores(player, lines_cleared)
        self.update_labels()

    def update_labels(self):
        for player in self.game.players:
            self.player_labels[player]['text'] = player + ": " + str(self.game.get_player_score(player))
        self.contribution_label['text'] = "Contribution: " + str(self.game.get_contribution("Player1")) + "%"

