import tkinter as tk
from random import randint

class Tetris:
    def __init__(self):
        self.root = tk.Tk()
        self.root.title("Tetris")
        self.root.geometry("400x500")
        self.canvas = tk.Canvas(self.root, width=400, height=500)
        self.canvas.pack()
        self.player_turn = 0
        self.players = ["Player1", "Player2", "Player3"]
        self.blocks = []
        self.scores = {"Player1": 0, "Player2": 0, "Player3": 0}
        self.create_board()
        self.draw_blocks()
        self.update_score()
        self.root.bind("<Key>", self.key_event)

    def create_board(self):
        self.board = []
        for i in range(20):
            row = []
            for j in range(10):
                row.append(0)
            self.board.append(row)

    def draw_blocks(self):
        self.canvas.delete("all")
        for i in range(20):
            for j in range(10):
                if self.board[i][j] == 1:
                    x1 = j * 40
                    y1 = i * 40
                    x2 = x1 + 40
                    y2 = y1 + 40
                    self.canvas.create_rectangle(x1, y1, x2, y2, fill="blue")

    def update_score(self):
        self.score_label = tk.Label(self.root, text="Score: Player1 - {} Player2 - {} Player3 - {}".format(self.scores["Player1"], self.scores["Player2"], self.scores["Player3"]))
        self.score_label.pack()
        self.turn_label = tk.Label(self.root, text="Turn: {}".format(self.players[self.player_turn]))
        self.turn_label.pack()

    def key_event(self, event):
        if event.keysym == "Left":
            self.move_left()
        elif event.keysym == "Right":
            self.move_right()
        elif event.keysym == "Down":
            self.move_down()
        elif event.keysym == "Up":
            self.rotate()
        self.draw_blocks()
        self.update_score()
        if self.player_turn < 2:
            self.player_turn += 1
        else:
            self.player_turn = 0

    def move_left(self):
        for i in range(20):
            for j in range(10):
                if self.board[i][j] == 1:
                    if j > 0 and self.board[i][j - 1] == 0:
                        self.board[i][j] = 0
                        self.board[i][j - 1] = 1

    def move_right(self):
        for i in range(20):
            for j in range(10):
                if self.board[i][j] == 1:
                    if j < 9 and self.board[i][j + 1] == 0:
                        self.board[i][j] = 0
                        self.board[i][j + 1] = 1

    def move_down(self):
        for i in range(19, -1, -1):
            for j in range(10):
                if self.board[i][j] == 1:
                    if i < 19 and self.board[i + 1][j] == 0:
                        self.board[i][j] = 0
                        self.board[i + 1][j] = 1

    def rotate(self):
        for i in range(20):
            for j in range(10):
                if self.board[i][j] == 1:
                    if i > 0 and j > 0 and self.board[i - 1][j - 1] == 0:
                        self.board[i][j] = 0
                        self.board[i - 1][j - 1] = 1

    def add_block(self):
        x = randint(0, 9)
        y = 0
        self.board[y][x] = 1

    def start_game(self):
        self.add_block()
        self.root.mainloop()

if __name__ == "__main__":
    game = Tetris()
    game.start_game()
